  ('promotion-6e2f88c7-moex-00101', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-112-3082b5f1', 'sub-promotion-6e2f88c7-04', NULL, 'single_choice', '關於依法行政原則，下列敘述何者錯誤？', '["依法行政係指行政必須依據制定法令而為之，並未受一般法律原理原則之拘束", "依法行政原則可再區分為法律保留原則與法律優位原則", "若以法規命令作為行政之依據，則該法規命令應有具體明確之法律授權", "縱然法律規範密度較寬鬆之給付行政，倘涉及公共利益之重大事項者，仍應受法律保留原則之 拘束 11030、11730 12330、12530 12830、13030 13130 14330、14530 30130、70130 71130"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:56+00:00", "source_pdf_sha1": "b796954d584f", "answer_pdf_sha1": "403e55525a12", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "125", "s": "0408", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
